(function(){var b="d39f46f26f5b",m="###### Modal Verbs\n- is an auxiliary verb that expresses necessity or possibility\n\n# Modal Verbs - Examples\n\n```merge-table\n{\n  \"rows\": [\n    [\n      {\n        \"content\": \"Modal Verb\",\n        \"header\": true,\n        \"bg\": \"#241d12\"\n      },\n      {\n        \"content\": \"Modal\",\n        \"header\": true,\n        \"bg\": \"#241d12\"\n      },\n      {\n        \"content\": \"Examples\",\n        \"header\": true,\n        \"bg\": \"#241d12\"\n      }\n    ],\n    [\n      {\n        \"content\": \"can\",\n        \"header\": true,\n        \"bg\": \"#241d12\"\n      },\n      \"- ability\\n- permission\\n- probability\",\n      \"- <code>I <strong>can</strong> speak Spanish</code>\\n- <code><strong>Can</strong> I go to the bathroom?</code>\\n- <code>It <strong>can't</strong> be Mark.</code>\"\n    ],\n    [\n      {\n        \"content\": \"could\",\n        \"header\": true,\n        \"bg\": \"#241d12\"\n      },\n      \"- past ability\\n- past permission\\n- probability (40%)\\n- request\",\n      \"- <code>He <strong>could</strong> swim when he was 6 years old</code>\\n- <code>He <strong>could</strong> go to the theater</code>\\n- <code>It <strong>could</strong> get much hotter in July</code>\\n- <code>I <strong>could</strong> lend you my notebook</code>\"\n    ],\n    [\n      {\n        \"content\": \"may\",\n        \"header\": true,\n        \"bg\": \"#241d12\"\n      },\n      \"- probability (50%)\\n- permission\",\n      \"- <code>It <strong>may</strong> snow tomorrow</code>\\n- <code><strong>May</strong> I come in?</code>\"\n    ],\n    [\n      {\n        \"content\": \"might\",\n        \"header\": true,\n        \"bg\": \"#241d12\"\n      },\n      \"- probability (35% or less)\",\n      \"- <code>It <strong>might</strong> rain today</code>\"\n    ],\n    [\n      {\n        \"content\": \"must\",\n        \"header\": true,\n        \"bg\": \"#241d12\"\n      },\n      \"- prohibition\\n- probability\",\n      \"- <code>You <strong>mustn't</strong> speak loudly here!</code>\\n- <code>It's quite dark, it <strong>must</strong> be 8 PM</code>\"\n    ],\n    [\n      {\n        \"content\": \"should\",\n        \"header\": true,\n        \"bg\": \"#241d12\"\n      },\n      \"- advice\",\n      \"- <code>You <strong>shouldn't</strong> smoke. It's unhealthy</code>\"\n    ],\n    [\n      {\n        \"content\": \"will\",\n        \"header\": true,\n        \"bg\": \"#241d12\"\n      },\n      \"- prediction\\n- spontaneous decision\",\n      \"- <code>I think he <strong>will</strong> study harder this time</code>\\n- <code>It's very hot today. I<strong> will</strong> open the window</code>\"\n    ]\n  ],\n  \"tableStyle\": \"letter-spacing: 0.0px;\"\n}\n```";if(window.__kgBody){window.__kgBody(b,m);}else{(window.__kgBodyQ=window.__kgBodyQ||[]).push([b,m]);}})();
